'use strict';

/**
* Generate a double-precision floating-point Vandermonde matrix.
*
* @module @stdlib/blas-ext-base-dvander
*
* @example
* import Float64Array from '@stdlib/array-float64';
* import dvander from '@stdlib/blas-ext-base-dvander';
*
* var x = new Float64Array( [ 1.0, 2.0, 3.0 ] );
* var out = new Float64Array( 9 );
*
* dvander( 'row-major', -1, 3, 3, x, 1, out, 3 );
* // out => <Float64Array>[ 1.0, 1.0, 1.0, 4.0, 2.0, 1.0, 9.0, 3.0, 1.0 ]
*
* @example
* import Float64Array from '@stdlib/array-float64';
* import dvander from '@stdlib/blas-ext-base-dvander';
*
* var x = new Float64Array( [ 1.0, 2.0, 3.0 ] );
* var out = new Float64Array( 9 );
*
* dvander.ndarray( -1, 3, 3, x, 1, 0, out, 3, 1, 0 );
* // out => <Float64Array>[ 1.0, 1.0, 1.0, 4.0, 2.0, 1.0, 9.0, 3.0, 1.0 ]
*/

// MODULES //

var join = require( 'path' ).join;
import tryRequire from '@stdlib/utils-try-require';
import isError from '@stdlib/assert-is-error';
import main from './main.js';


// MAIN //

var dvander;
var tmp = tryRequire( join( __dirname, './native.js' ) );
if ( isError( tmp ) ) {
	dvander = main;
} else {
	dvander = tmp;
}


// EXPORTS //

export default dvander;

